import{_ as e,c as o,o as t,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Google Cloud: G3 Pro 额度查询 | opencode-mystatus","description":"学习 Google Cloud 的 G3 Pro、G3 Image、G3 Flash 和 Claude 模型额度查询方法。通过 mystatus 插件快速查看多账号剩余额度和重置时间。","frontmatter":{"title":"Google Cloud: G3 Pro 额度查询 | opencode-mystatus","sidebarTitle":"Google Cloud","subtitle":"Google Cloud: G3 Pro 额度查询","description":"学习 Google Cloud 的 G3 Pro、G3 Image、G3 Flash 和 Claude 模型额度查询方法。通过 mystatus 插件快速查看多账号剩余额度和重置时间。","tags":["Google Cloud","Antigravity","额度查询"],"prerequisite":["start-quick-start","start-using-mystatus"],"order":4},"headers":[],"relativePath":"zh/vbgate/opencode-mystatus/platforms/google-usage/index.md","filePath":"zh/vbgate/opencode-mystatus/platforms/google-usage/index.md"}'),s={name:"zh/vbgate/opencode-mystatus/platforms/google-usage/index.md"};function n(i,a,d,r,p,c){return t(),o("div",null,[...a[0]||(a[0]=[l(`<h1 id="google-cloud-额度查询-g3-pro-image-flash-和-claude" tabindex="-1">Google Cloud 额度查询：G3 Pro/Image/Flash 和 Claude <a class="header-anchor" href="#google-cloud-额度查询-g3-pro-image-flash-和-claude" aria-label="Permalink to &quot;Google Cloud 额度查询：G3 Pro/Image/Flash 和 Claude&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>查看 Google Cloud Antigravity 账号的 4 个模型额度</li><li>理解每个模型的重置时间和剩余百分比</li><li>管理多个 Google Cloud 账号的额度使用</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>Google Cloud Antigravity 提供多个模型（G3 Pro、G3 Image、G3 Flash、Claude），每个模型有独立的额度和重置时间。你需要：</p><ul><li>分别登录 Google Cloud 控制台查看每个模型的状态</li><li>手动计算剩余额度和重置时间</li><li>管理多个账号时更加混乱</li></ul><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p>当你：</p><ul><li>想快速了解所有 Google Cloud 模型的剩余额度</li><li>需要规划在不同模型间的使用分配</li><li>有多个 Google Cloud 账号需要统一管理</li></ul><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前置检查</p><ol><li><strong>已安装 mystatus 插件</strong>：参考 <a href="/docs/opencodedocs/zh/vbgate/opencode-mystatus/start/quick-start/">快速开始</a></li><li><strong>已配置 Google Cloud 认证</strong>：需要先安装 <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a> 插件完成 OAuth 认证</li><li><strong>认证文件存在</strong>：<code>~/.config/opencode/antigravity-accounts.json</code> 至少包含一个账号</li></ol></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Google Cloud Antigravity 通过 OAuth 机制认证，每个账号有独立的 Refresh Token。mystatus 插件会：</p><ol><li>读取 <code>antigravity-accounts.json</code> 获取所有已配置账号</li><li>使用 Refresh Token 刷新 Access Token</li><li>调用 Google Cloud API 获取所有模型的额度</li><li>按账号分组显示 4 个模型的额度和重置时间</li></ol><h2 id="google-cloud-支持的模型" tabindex="-1">Google Cloud 支持的模型 <a class="header-anchor" href="#google-cloud-支持的模型" aria-label="Permalink to &quot;Google Cloud 支持的模型&quot;">​</a></h2><p>mystatus 显示以下 4 个模型的额度：</p><table tabindex="0"><thead><tr><th>显示名称</th><th>模型 Key（主/备）</th><th>说明</th></tr></thead><tbody><tr><td>G3 Pro</td><td><code>gemini-3-pro-high</code> / <code>gemini-3-pro-low</code></td><td>Gemini 3 Pro 高性能版本</td></tr><tr><td>G3 Image</td><td><code>gemini-3-pro-image</code></td><td>Gemini 3 Pro 图像生成</td></tr><tr><td>G3 Flash</td><td><code>gemini-3-flash</code></td><td>Gemini 3 Flash 快速版本</td></tr><tr><td>Claude</td><td><code>claude-opus-4-5-thinking</code> / <code>claude-opus-4-5</code></td><td>Claude Opus 4.5 模型</td></tr></tbody></table><p><strong>主 Key 和备 Key 机制</strong>：</p><ul><li>API 响应中可能只返回主 key 或备 key 的数据</li><li>mystatus 会自动尝试获取任一 key 的额度</li><li>例如：如果 <code>gemini-3-pro-high</code> 没有数据，会尝试 <code>gemini-3-pro-low</code></li></ul><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-执行查询命令" tabindex="-1">第 1 步：执行查询命令 <a class="header-anchor" href="#第-1-步-执行查询命令" aria-label="Permalink to &quot;第 1 步：执行查询命令&quot;">​</a></h3><p><strong>为什么</strong> 快速获取所有 Google Cloud 账号的额度信息</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><p><strong>你应该看到</strong> 包含所有已配置平台的额度信息，其中 Google Cloud 部分会显示类似以下内容：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Google Cloud Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Flash   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>Claude     2d 9h      ░░░░░░░░░░░░░░░░░░░░ 0%</span></span></code></pre></div><h3 id="第-2-步-理解输出格式" tabindex="-1">第 2 步：理解输出格式 <a class="header-anchor" href="#第-2-步-理解输出格式" aria-label="Permalink to &quot;第 2 步：理解输出格式&quot;">​</a></h3><p><strong>为什么</strong> 快速定位关键信息：剩余额度和重置时间</p><p>每行格式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[模型名] [重置时间] [进度条] [剩余百分比]</span></span></code></pre></div><p><strong>字段说明</strong>：</p><ul><li><strong>模型名</strong>：G3 Pro、G3 Image、G3 Flash、Claude</li><li><strong>重置时间</strong>：距离下次额度的剩余时间（如 <code>4h 59m</code>、<code>2d 9h</code>）</li><li><strong>进度条</strong>：可视化显示剩余百分比</li><li><strong>剩余百分比</strong>：0-100 的数值</li></ul><p><strong>你应该看到</strong> 每个模型一行，清晰显示额度和重置时间</p><h3 id="第-3-步-查看多账号情况" tabindex="-1">第 3 步：查看多账号情况 <a class="header-anchor" href="#第-3-步-查看多账号情况" aria-label="Permalink to &quot;第 3 步：查看多账号情况&quot;">​</a></h3><p><strong>为什么</strong> 如果你有多个 Google Cloud 账号，会分别显示</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### another@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     2h 30m     ████████████░░░░░░░░░ 75%</span></span>
<span class="line"><span>G3 Image   2h 30m     ████████████░░░░░░░░░ 75%</span></span></code></pre></div><p><strong>你应该看到</strong> 每个账号单独一个区块，包含该账号的 4 个模型额度</p><h3 id="第-4-步-检查额度警告" tabindex="-1">第 4 步：检查额度警告 <a class="header-anchor" href="#第-4-步-检查额度警告" aria-label="Permalink to &quot;第 4 步：检查额度警告&quot;">​</a></h3><p><strong>为什么</strong> 避免超额使用导致服务中断</p><p>如果任一模型的使用率超过 80%，会显示警告提示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     1h 30m     ████░░░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span>G3 Image   1h 30m     ████░░░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>⚠️ 使用率已达到或超过 80%</span></span></code></pre></div><p><strong>你应该看到</strong> 警告提示出现在对应账号的模型列表下方</p><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>完成以下检查，确保你做对了：</p><ul><li>[ ] 执行 <code>/mystatus</code> 后能看到 Google Cloud 额度信息</li><li>[ ] 能理解 4 个模型的名称和重置时间</li><li>[ ] 能识别进度条和剩余百分比</li><li>[ ] 如果有多账号，能看到所有账号的额度</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="问题-1-看不到-google-cloud-额度" tabindex="-1">问题 1：看不到 Google Cloud 额度 <a class="header-anchor" href="#问题-1-看不到-google-cloud-额度" aria-label="Permalink to &quot;问题 1：看不到 Google Cloud 额度&quot;">​</a></h3><p><strong>可能原因</strong>：</p><ul><li>未安装 opencode-antigravity-auth 插件</li><li>未完成 Google OAuth 认证</li><li><code>antigravity-accounts.json</code> 文件不存在或为空</li></ul><p><strong>解决方案</strong>：</p><ol><li>安装 opencode-antigravity-auth 插件</li><li>按照 GitHub 仓库的说明完成认证</li><li>重新执行 <code>/mystatus</code></li></ol><h3 id="问题-2-某个账号显示错误" tabindex="-1">问题 2：某个账号显示错误 <a class="header-anchor" href="#问题-2-某个账号显示错误" aria-label="Permalink to &quot;问题 2：某个账号显示错误&quot;">​</a></h3><p><strong>可能原因</strong>：</p><ul><li>Refresh Token 过期</li><li>projectId 缺失</li></ul><p><strong>错误示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user@gmail.com: No project ID found</span></span></code></pre></div><p><strong>解决方案</strong>：</p><ol><li>重新使用 opencode-antigravity-auth 插件认证该账号</li><li>确保在认证过程中正确设置了项目 ID</li></ol><h3 id="问题-3-模型显示-或重置时间异常" tabindex="-1">问题 3：模型显示&quot;-&quot;或重置时间异常 <a class="header-anchor" href="#问题-3-模型显示-或重置时间异常" aria-label="Permalink to &quot;问题 3：模型显示&quot;-&quot;或重置时间异常&quot;">​</a></h3><p><strong>可能原因</strong>：</p><ul><li>API 返回的 resetTime 字段缺失或格式异常</li><li>该模型暂无额度信息</li></ul><p><strong>解决方案</strong>：</p><ul><li>这是正常的，mystatus 会显示&quot;-&quot;表示数据不可用</li><li>如所有模型都显示&quot;-&quot;，检查网络连接或 Google Cloud API 状态</li></ul><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>Google Cloud Antigravity 支持 4 个模型：G3 Pro、G3 Image、G3 Flash、Claude</li><li>每个模型有独立的额度和重置时间</li><li>支持多账号管理，每个账号单独显示</li><li>使用率超过 80% 时会显示警告提示</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../advanced/google-setup/">Google Cloud 高级配置：多账号和模型管理</a></strong>。</p><p>你会学到：</p><ul><li>如何添加和管理多个 Google Cloud 账号</li><li>理解 4 个模型的映射关系</li><li>projectId 和 managedProjectId 的区别</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>模型配置</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L69-L78" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>69-78</td></tr><tr><td>账号查询逻辑</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L304-L370" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>304-370</td></tr><tr><td>Token 刷新</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L162-L184" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>162-184</td></tr><tr><td>额度提取</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L132-L157" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>132-157</td></tr><tr><td>格式化输出</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L265-L294" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>265-294</td></tr><tr><td>类型定义</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L78-L94" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>78-94</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>GOOGLE_QUOTA_API_URL = &quot;https://cloudcode-pa.googleapis.com/v1internal:fetchAvailableModels&quot;</code>：Google Cloud 额度查询 API</li><li><code>GOOGLE_TOKEN_REFRESH_URL = &quot;https://oauth2.googleapis.com/token&quot;</code>：OAuth Token 刷新 API</li><li><code>USER_AGENT = &quot;antigravity/1.11.9 windows/amd64&quot;</code>：API 请求 User-Agent</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>queryGoogleUsage()</code>：查询所有 Antigravity 账号的额度</li><li><code>fetchAccountQuota()</code>：查询单个账号的额度</li><li><code>extractModelQuotas()</code>：从 API 响应中提取 4 个模型的额度</li><li><code>formatAccountQuota()</code>：格式化单个账号的额度显示</li></ul><p><strong>模型映射规则</strong>：</p><ul><li>G3 Pro 支持 <code>gemini-3-pro-high</code> 和 <code>gemini-3-pro-low</code>，优先使用主 key</li><li>Claude 支持 <code>claude-opus-4-5-thinking</code> 和 <code>claude-opus-4-5</code>，优先使用主 key</li><li>G3 Image 和 G3 Flash 只有一个 key</li></ul></details>`,69)])])}const h=e(s,[["render",n]]);export{u as __pageData,h as default};
